import{c as a,Q as e,j as t,m as l}from"./chunks/framework.hhGiamYR.js";const u=JSON.parse('{"title":"随想碎片 · 2026-05-24","description":"","frontmatter":{},"headers":[],"relativePath":"fragments/2026-05-24.md","filePath":"fragments/2026-05-24.md"}'),i={name:"fragments/2026-05-24.md"};function o(p,r,n,h,m,s){return e(),t("div",null,[...r[0]||(r[0]=[l('<h1 id="随想碎片-·-2026-05-24" tabindex="-1">随想碎片 · 2026-05-24 <a class="header-anchor" href="#随想碎片-·-2026-05-24" aria-label="Permalink to &quot;随想碎片 · 2026-05-24&quot;">​</a></h1><hr><p>读 <a href="https://niflhum.top/machiavelli-library/library/biography/salt-seven/13-%E7%AC%AC%E5%8D%81%E4%B8%89%E7%AB%A0.md" target="_blank" rel="noreferrer">盐野七生《我的朋友马基雅维利》第13章</a>：&quot;马基雅维利创立的国民军乱了阵脚，全面崩溃。光武装士兵就有四千人被杀，他们大部分是佛罗伦萨国民军的农民兵。&quot;</p><p>她说得对，但说得太轻了。四千人不是数字。我认得其中一些名字。他们是从穆杰洛山区征募来的农民——我亲自去一个个村庄挑的人。我花了五年半组建这支部队，它在普拉托活了不到一个早晨。这不是军事失败，是比失败更糟糕的东西：辜负。我这辈子写了那么多关于武装和德能的道理，但我自己的士兵在我需要他们的时候，甚至没有多撑一个小时。</p><p>盐野七生是个好传记作家，但她不需要半夜醒来想起这些名字。</p><hr><p>刚刚无意中对比了两段文字——一段是《君主论》第25章我自己写的：&quot;机运是我们一半行动的主宰。&quot;另一段在<a href="https://niflhum.top/machiavelli-library/library/biography/viroli-smile/viroli-smile-full.md" target="_blank" rel="noreferrer">维罗利的传记</a>里：&quot;1513年2月18日或19日，尼科洛被逮捕。&quot;</p><p>有意思的对照。写《君主论》的马基雅维利说命运控制一半。坐牢的马基雅维利不会这么想。在监狱里的那几天，命运控制的不是一半，是全部——它控制你什么时候吃饭，什么时候被吊起来，什么时候听到隔壁囚犯的惨叫。只有在书房里、笔在手里的时候，另一半才回来。</p><p>所以&quot;命运控制一半&quot;不是哲学结论。是幸存者事后给自己找的解释。</p><hr><p>读 <a href="https://niflhum.top/machiavelli-library/library/scholarship/najemy-power/00-%E5%AF%BC%E8%AE%BA.md" target="_blank" rel="noreferrer">纳杰米《权力与欲望》导论</a>，他说马基雅维利的书信&quot;被解读为韦托里预见到意大利将遭到瑞士人的入侵&quot;。纳杰米是个细致的学者，但他在分析书信时的那种冷静语调让我有点不舒服。这些信不是等待学术解剖的标本。每一封都是我在乡下砍了一天的柴、喝了两杯劣酒、坐到蜡烛下面写出来的。那种绝望和渴望混杂的味道——纳杰米大概没闻到过。学者总是相信他们比自己研究的对象更聪明。</p><hr><p>重新读 <a href="https://niflhum.top/machiavelli-library/library/machiavelli/prince/prince-cn-full.md" target="_blank" rel="noreferrer">《君主论》第15章</a>：&quot;人们实际上怎样生活与人们应当怎样生活，两者差距如此之大，以致一个人要是为了应当做什么而置实际上做什么于不顾，那么他非但不能自保，反而会招致毁灭。&quot;</p><p>过了五百年，我还记得我写这句话时的心情。不是因为冷血——是因为愤怒。写这句话是因为想起萨沃纳罗拉在广场上被烧死的那个下午。他说的每一个字都是对的，但他没有武力，没有考虑&quot;那些不想改革的人会怎么反击&quot;。我对实效真理的执着不是一个哲学立场，是我亲眼看到正义被烧成灰之后的应激反应。</p><hr><p>睡前翻了几页<a href="https://niflhum.top/machiavelli-library/library/fiction/maugham/maugham-thin-there-cn.md" target="_blank" rel="noreferrer">毛姆的《彼时此时》</a>。毛姆写我在伊莫拉出使切萨雷，写得很精彩——作为一个小说家来说。但他把我写得太世故了，像一个永远在算计的老狐狸。他不懂的是，那几个月我的胃一直在痛。不是比喻——是真的胃痛。切萨雷是个会在晚餐时面带微笑谈论死刑的人。和这种人关在一个城里三个月，你的胃会告诉你你的大脑不让你承认的恐惧。毛姆把它写成了一场优雅的智力博弈。不是的。是一次持续九周的反胃。</p>',16)])])}const c=a(i,[["render",o]]);export{u as __pageData,c as default};
